from datetime import date, timedelta

@dataclass
class CommEvent:
    stakeholder_name: str
    comm_type: str           # "weekly-status" / "steering-report" / "exec-brief" / "1:1"
    due_date: date
    channel: str
    generated: bool = False

def build_q3_comms_calendar(
    stakeholders: list[Stakeholder],
    quarter_start: date,
    quarter_end: date,
) -> list[CommEvent]:
    """Generate a full-quarter communication calendar from the stakeholder register."""
    events: list[CommEvent] = []
    current = quarter_start

    while current <= quarter_end:
        week_number = (current - quarter_start).days // 7 + 1

        for s in stakeholders:
            strategy = s.strategy

            # Weekly: manage closely + keep informed
            if strategy in (EngagementStrategy.MANAGE_CLOSELY,
                            EngagementStrategy.KEEP_INFORMED):
                events.append(CommEvent(
                    s.name, "weekly-status", current, s.preferred_channel
                ))

            # Bi-weekly: manage closely gets steering report
            if strategy == EngagementStrategy.MANAGE_CLOSELY and week_number % 2 == 0:
                events.append(CommEvent(
                    s.name, "steering-report", current, "email"
                ))

        # Monthly: keep satisfied gets exec brief (first week of each month)
        if current.day <= 7:
            for s in stakeholders:
                if s.strategy == EngagementStrategy.KEEP_SATISFIED:
                    events.append(CommEvent(s.name, "exec-brief", current, s.preferred_channel))

        current += timedelta(weeks=1)

    return events

calendar = build_q3_comms_calendar(
    stakeholders=stakeholders,
    quarter_start=date(2025, 7, 7),
    quarter_end=date(2025, 9, 26),
)
print(f"Q3 communication events: {len(calendar)}")
# → Q3 communication events: 87
